import java.util.List;
import java.util.stream.Stream;

List<String> names = List.of("Alice", "Bob", "Charlie", "David");

// Source → Intermediate operations → Terminal operation
names.stream()              // Source: create stream from List
     .filter(s -> s.length() > 3)  // Intermediate: length 4 or more
     .map(String::toUpperCase)     // Intermediate: convert to uppercase
     .forEach(System.out::println); // Terminal: print output
// Output: ALICE, CHARLIE, DAVID

import java.util.Arrays;
import java.util.List;
import java.util.stream.Stream;

// 1. From a collection
List<String> list = List.of("A", "B", "C");
Stream<String> s1 = list.stream();

// 2. Directly with Stream.of()
Stream<String> s2 = Stream.of("X", "Y", "Z");

// 3. From an array
String[] arr = {"a", "b", "c"};
Stream<String> s3 = Arrays.stream(arr);

// 4. Empty Stream
Stream<String> s4 = Stream.empty();

// 5. Infinite Stream (limited with limit)
Stream<Integer> s5 = Stream.iterate(0, n -> n + 2).limit(5);
s5.forEach(System.out::println); // 0, 2, 4, 6, 8

// 6. Generate
Stream<Double> s6 = Stream.generate(Math::random).limit(3);

List<String> list = List.of("A", "B", "C");
Stream<String> stream = list.stream();

// Execute a terminal operation
stream.forEach(System.out::println);

// Trying to reuse the same Stream throws an exception
try {
    stream.forEach(System.out::println);
} catch (IllegalStateException e) {
    System.out.println("Stream cannot be reused");
    // Output: Stream cannot be reused
}

// Stream.of(array) vs Arrays.stream(array)
String[] arr = {"A", "B", "C"};

Stream<String[]> s1 = Stream.of(arr);   // Stream<String[]>: 1 element
Stream<String> s2 = Arrays.stream(arr); // Stream<String>: 3 elements

System.out.println(Stream.of(arr).count());    // 1
System.out.println(Arrays.stream(arr).count()); // 3

// iterate since Java 9
Stream.iterate(1, n -> n <= 10, n -> n * 2)
      .forEach(System.out::println); // 1, 2, 4, 8

List<String> names = List.of("Alice", "Bob", "Charlie", "David", "Eve");

// filter: keep only elements matching the condition
names.stream()
     .filter(s -> s.length() >= 4)
     .forEach(System.out::println);
// Output: Alice, Charlie, David

// map: transform each element
names.stream()
     .map(String::toUpperCase)
     .forEach(System.out::println);
// Output: ALICE, BOB, CHARLIE, DAVID, EVE

// Combining filter + map
names.stream()
     .filter(s -> s.startsWith("C"))
     .map(String::toLowerCase)
     .forEach(System.out::println);
// Output: charlie

// Flatten a list of lists
List<List<String>> nested = List.of(
    List.of("A", "B"),
    List.of("C", "D"),
    List.of("E")
);

nested.stream()
      .flatMap(List::stream)
      .forEach(System.out::println);
// Output: A, B, C, D, E

// Transform strings into a Stream of characters
List<String> words = List.of("Hello", "World");
words.stream()
     .flatMap(s -> s.chars().mapToObj(c -> (char) c))
     .forEach(System.out::print);
// Output: HelloWorld

List<Integer> nums = List.of(3, 1, 4, 1, 5, 9, 2, 6, 5, 3);

// distinct: remove duplicates
nums.stream()
    .distinct()
    .forEach(n -> System.out.print(n + " "));
// Output: 3 1 4 5 9 2 6

System.out.println();

// sorted: sort
nums.stream()
    .sorted()
    .forEach(n -> System.out.print(n + " "));
// Output: 1 1 2 3 3 4 5 5 6 9

System.out.println();

// peek: for debugging
nums.stream()
    .filter(n -> n > 3)
    .peek(n -> System.out.println("filtered: " + n))
    .map(n -> n * 10)
    .forEach(n -> System.out.println("result: " + n));
// filtered: 4 → result: 40, filtered: 5 → result: 50, ...

// Confirming lazy evaluation
Stream<String> stream = List.of("A", "B", "C").stream()
    .peek(s -> System.out.println("peek: " + s))
    .filter(s -> s.equals("B"));

System.out.println("Before terminal operation");
// peek is not executed up to this point

stream.forEach(System.out::println);
// Output:
// Before terminal operation
// peek: A
// peek: B
// B
// peek: C

List<String> names = List.of("Alice", "Bob", "Charlie");

// forEach: execute an action on each element
names.stream().forEach(System.out::println);
// Output: Alice, Bob, Charlie

// count: return the number of elements
long count = names.stream()
                  .filter(s -> s.length() > 3)
                  .count();
System.out.println(count); // 2

// collect: collect into a list
List<String> upper = names.stream()
                          .map(String::toUpperCase)
                          .collect(Collectors.toList());
System.out.println(upper); // [ALICE, BOB, CHARLIE]

// toArray: convert to an array
String[] arr = names.stream().toArray(String[]::new);
System.out.println(Arrays.toString(arr)); // [Alice, Bob, Charlie]

List<Integer> nums = List.of(1, 2, 3, 4, 5);

// findFirst: get the first element
Optional<Integer> first = nums.stream()
    .filter(n -> n > 3)
    .findFirst();
System.out.println(first.get()); // 4

// anyMatch: does any element satisfy the condition?
boolean any = nums.stream().anyMatch(n -> n > 4);
System.out.println(any); // true

// allMatch: do all elements satisfy the condition?
boolean all = nums.stream().allMatch(n -> n > 0);
System.out.println(all); // true

// noneMatch: does no element satisfy the condition?
boolean none = nums.stream().noneMatch(n -> n > 10);
System.out.println(none); // true

List<Integer> nums = List.of(1, 2, 3, 4, 5);

// Without initial value: returns Optional<Integer>
Optional<Integer> sum1 = nums.stream()
    .reduce((a, b) -> a + b);
System.out.println(sum1.get()); // 15

// With initial value: returns int
int sum2 = nums.stream()
    .reduce(0, Integer::sum);
System.out.println(sum2); // 15

// Maximum value
Optional<Integer> max = nums.stream()
    .reduce(Integer::max);
System.out.println(max.get()); // 5

// String concatenation
String joined = List.of("A", "B", "C").stream()
    .reduce("", (a, b) -> a + b);
System.out.println(joined); // ABC

