import java.util.stream.IntStream;

// range: 1 to 4 (5 is not included)
IntStream.range(1, 5)
    .forEach(n -> System.out.print(n + " "));
// Output: 1 2 3 4

System.out.println();

// rangeClosed: 1 to 5 (5 is included)
IntStream.rangeClosed(1, 5)
    .forEach(n -> System.out.print(n + " "));
// Output: 1 2 3 4 5

System.out.println();

// range() with zero elements
System.out.println(IntStream.range(5, 5).count()); // 0

// rangeClosed() with one element
System.out.println(IntStream.rangeClosed(5, 5).count()); // 1

IntStream nums = IntStream.of(10, 20, 30, 40, 50);

// Note: Streams can only be used once, so create a new one each time
System.out.println(IntStream.of(10, 20, 30, 40, 50).sum());
// Output: 150

System.out.println(IntStream.of(10, 20, 30, 40, 50).average());
// Output: OptionalDouble[30.0]

System.out.println(IntStream.of(10, 20, 30, 40, 50).max());
// Output: OptionalInt[50]

System.out.println(IntStream.of(10, 20, 30, 40, 50).min());
// Output: OptionalInt[10]

// summaryStatistics: get all at once
IntSummaryStatistics stats = IntStream.of(10, 20, 30, 40, 50)
    .summaryStatistics();
System.out.println("Count: " + stats.getCount());   // 5
System.out.println("Sum: " + stats.getSum());       // 150
System.out.println("Average: " + stats.getAverage()); // 30.0

// Stream<String> → IntStream
List<String> words = List.of("Java", "Go", "Python");
IntStream lengths = words.stream().mapToInt(String::length);
System.out.println(lengths.sum()); // 12

// IntStream → Stream<Integer> (boxed)
List<Integer> boxed = IntStream.rangeClosed(1, 5)
    .boxed()
    .collect(Collectors.toList());
System.out.println(boxed); // [1, 2, 3, 4, 5]

// IntStream → Stream<String> (mapToObj)
List<String> strs = IntStream.range(1, 4)
    .mapToObj(n -> "Item" + n)
    .collect(Collectors.toList());
System.out.println(strs); // [Item1, Item2, Item3]

// IntStream → LongStream → DoubleStream
IntStream.range(1, 4)
    .asDoubleStream()
    .forEach(d -> System.out.print(d + " "));
// Output: 1.0 2.0 3.0

// Cannot use Collectors.toList() directly on IntStream
// IntStream.range(1, 4).collect(Collectors.toList()); // Compile error

// Convert with boxed() first
List<Integer> list = IntStream.range(1, 4)
    .boxed()
    .collect(Collectors.toList());

// OptionalInt's get-family methods
OptionalInt max = IntStream.of(3, 1, 4).max();
System.out.println(max.getAsInt()); // 4 (getAsInt, not get)

// Stream<Integer> → IntStream
List<Integer> nums = List.of(10, 20, 30);
int sum = nums.stream()
    .mapToInt(Integer::intValue)
    .sum();
System.out.println(sum); // 60
